// Extract file binary + metadata from webhook payload
const input = $input.first();
const json = input.json;
const binary = input.binary;

// Get metadata from form fields or JSON body
const projectName = json.project_name || json.projectName || 'Unknown Project';
const drawingNumber = json.drawing_number || json.drawingNumber || 'Unknown';
const fileName = json.file_name || json.fileName || 'drawing.pdf';

// Check if we have binary data (file upload) or a URL
let hasFile = false;
let fileUrl = json.file_url || json.fileUrl || json.url || '';

if (binary && binary.data) {
  hasFile = true;
} else if (binary && binary.file) {
  hasFile = true;
}

if (!hasFile && !fileUrl) {
  throw new Error('No PDF file or file_url provided in webhook payload. Send a multipart/form-data POST with a "data" or "file" field containing the PDF.');
}

// Convert binary to base64 for Claude API
let base64Data = '';
let mimeType = 'application/pdf';
if (hasFile) {
  const binaryKey = binary.data ? 'data' : 'file';
  base64Data = binary[binaryKey].data; // n8n stores binary as base64 already
  mimeType = binary[binaryKey].mimeType || 'application/pdf';
}

return [{
  json: {
    has_file: hasFile,
    file_url: fileUrl,
    base64_data: base64Data,
    mime_type: mimeType,
    file_name: fileName,
    project_name: projectName,
    drawing_number: drawingNumber
  },
  binary: input.binary  // Pass binary through for LlamaParse upload
}];

// Prepare data for LlamaParse upload
// Pass through binary + metadata
const input = $input.first();
const fileData = input.json;

return [{
  json: {
    has_file: fileData.has_file,
    file_url: fileData.file_url,
    file_name: fileData.file_name,
    project_name: fileData.project_name,
    drawing_number: fileData.drawing_number
  },
  binary: (() => {
    const bin = input.binary || {};
    const keys = Object.keys(bin);
    if (keys.length > 0) {
      return { data: bin[keys[0]] };
    }
    return {};
  })()
}];

// Poll Counter — LlamaParse Parse Job
const items = $input.all();
const item = items[0].json;
const pollCount = (item.poll_count || 0) + 1;
const maxPolls = 15;
const jobId = item.id || item.job_id || $('Submit Parse Job').first().json.id;

if (pollCount > maxPolls) {
  throw new Error('LlamaParse Parse job timed out after ' + maxPolls + ' polls. Job ID: ' + jobId);
}

return [{
  json: {
    ...item,
    job_id: jobId,
    poll_count: pollCount,
    max_polls: maxPolls,
    poll_exceeded: pollCount > maxPolls
  }
}];

// Poll Counter — LlamaParse Extract Job
const items = $input.all();
const item = items[0].json;
const pollCount = (item.poll_count || 0) + 1;
const maxPolls = 15;
const jobId = item.id || item.job_id || $('Submit Extract Job').first().json.id;

if (pollCount > maxPolls) {
  throw new Error('LlamaParse Extract job timed out after ' + maxPolls + ' polls. Job ID: ' + jobId);
}

return [{
  json: {
    ...item,
    job_id: jobId,
    poll_count: pollCount,
    max_polls: maxPolls,
    poll_exceeded: pollCount > maxPolls
  }
}];

// Prepare LlamaParse Output — Combines Parse result (markdown) and Extract result (JSON)
// Input (direct): Get Extract JSON output
// Reference (by name): Get Parse Markdown output

const extractResult = $input.first().json;  // from Get Extract JSON
const parseResult = $('Get Parse Markdown').first().json;  // from Get Parse Markdown

const fileInfo = $('Extract File Data').first().json;

// Parse markdown text — LlamaParse returns { markdown: "..." } from /result/markdown
const llamaMarkdown = parseResult?.markdown
  || parseResult?.text
  || (typeof parseResult === 'string' ? parseResult : '')
  || '';

// Extract structured JSON — LlamaParse returns schema output from /result/json
const llamaExtract = extractResult || {};

return [{
  json: {
    source: 'llamaparse',
    llamaparse_markdown: llamaMarkdown,
    llamaparse_extract: llamaExtract,
    file_url: fileInfo.file_url || '',
    project_name: fileInfo.project_name || 'Unknown Project',
    drawing_number: fileInfo.drawing_number || 'Unknown'
  }
}];

// Prepare Claude Input — Updated for AI Agent node
// Outputs chatInput prompt + binary (PDF) for Claude Direct Extract AI Agent
// System prompt lives in the AI Agent node System Message field

const fileData = $('Extract File Data').first().json;
const binaryData = $('Extract File Data').first().binary || {};

return [{
  json: {
    chatInput: "Extract all mechanical equipment schedules from this construction drawing. Return ONLY valid JSON matching the PhaseAlpha output schema.",
    file_name: fileData.file_name || 'drawing.pdf',
    project_name: fileData.project_name || 'Unknown Project',
    drawing_number: fileData.drawing_number || 'Unknown'
  },
  binary: binaryData
}];

// PRE-FLIGHT CHECK
const fileInfo = $('Extract File Data').first().json;

// ── SOURCE A: LlamaParse ──
const llamaRaw = $('Prepare LlamaParse Output').first().json;
const llamaMarkdown = llamaRaw?.llamaparse_markdown || '';
const llamaTableCount = (llamaMarkdown.match(/###\s+[A-Z]/g) || []).length;

// ── SOURCE B: Claude Direct Extract (AI Agent output) ──
const claudeRaw = $('Claude Direct Extract').first().json;

let claudeText = '';
const isAgentOutput = !!claudeRaw?.output;
if (isAgentOutput) {
  claudeText = claudeRaw.output;
} else if (claudeRaw?.content && Array.isArray(claudeRaw.content)) {
  claudeText = claudeRaw.content.map(b => b.text || '').join('');
} else {
  claudeText = '';
}

// Detect API-level truncation (HTTP Request path — stop_reason)
const apiTruncated = claudeRaw?.stop_reason === 'max_tokens';

// Parse Claude output — strip markdown fences if present
const cleanText = claudeText.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
let claudeParsed = null;
let parseError = null;
try {
  claudeParsed = JSON.parse(cleanText);
} catch (e) {
  parseError = e.message;
}

const announcedMatch = claudeText.match(/Detected\s+(\d+)\s+schedule/i);
const announcedCount = announcedMatch ? parseInt(announcedMatch[1]) : null;
const extractedCount = claudeParsed?.mechanical_equipment_schedules?.length || 0;
const declaredIncomplete = claudeParsed?.incomplete === true;
const remainingSchedules = claudeParsed?.remaining_schedules || [];

// ── BUILD ERRORS ──
const errors = [];

if (!llamaMarkdown || llamaMarkdown.trim().length === 0) {
  errors.push('SOURCE_A EMPTY: LlamaParse returned no markdown content.');
}

if (!claudeText || claudeText.trim().length === 0) {
  errors.push('SOURCE_B EMPTY: Claude Direct Extract returned no output.');
}

if (parseError) {
  errors.push('SOURCE_B PARSE FAILED: Claude output is not valid JSON. Error: ' + parseError);
}

if (apiTruncated) {
  errors.push(
    'SOURCE_B TRUNCATED BY API: Claude Direct Extract hit max_tokens limit (stop_reason=max_tokens). ' +
    'Extracted ' + extractedCount + ' schedules before cutoff. ' +
    'Fix: verify Anthropic Chat Model maxTokensToSample is set to 32000.'
  );
}

if (declaredIncomplete) {
  errors.push(
    'SOURCE_B INCOMPLETE: Claude declared incomplete=true. ' +
    'Extracted ' + extractedCount + ' schedules, remaining: [' + remainingSchedules.join(', ') + '].'
  );
}

if (announcedCount !== null && extractedCount < announcedCount) {
  errors.push(
    'SOURCE_B SCHEDULE GAP: Claude announced ' + announcedCount + ' schedules but only ' +
    extractedCount + ' extracted. Missing ' + (announcedCount - extractedCount) + ' schedule(s).'
  );
}

const flags = {
  source_a_has_content: llamaMarkdown.length > 0,
  source_a_table_count_approx: llamaTableCount,
  source_b_output_format: isAgentOutput ? 'ai_agent' : 'http_request',
  source_b_api_truncated: apiTruncated,
  source_b_parse_error: parseError,
  source_b_declared_incomplete: declaredIncomplete,
  source_b_announced_count: announcedCount,
  source_b_extracted_count: extractedCount,
  source_b_remaining: remainingSchedules,
  preflight_passed: errors.length === 0,
  preflight_errors: errors
};

return [{
  json: {
    preflight_status: errors.length === 0 ? 'PASS' : 'FAIL',
    flags,
    source_a: llamaRaw,
    source_b_parsed: claudeParsed,
    source_b_text: claudeText,
    file_info: fileInfo,
    error_summary: errors.length > 0 ? errors.join(' | ') : null
  }
}];

// Prepare Agent Input — Fixed
// Reads SOURCE_A and SOURCE_B from Pre-Flight Check output
// PDF binary from Webhook Trigger — AI Agent passthroughBinaryImages handles conversion

const preflight = $input.first().json;
const fileInfo = preflight.file_info;
const llamaData = preflight.source_a;
const claudeParsed = preflight.source_b_parsed;

// SOURCE_A: LlamaParse markdown (compact — no bBox noise)
const sourceAText = llamaData?.llamaparse_markdown || 'SOURCE A NOT AVAILABLE';

// SOURCE_B: Claude structured JSON
const sourceBText = claudeParsed
  ? JSON.stringify(claudeParsed, null, 2)
  : 'SOURCE B NOT AVAILABLE';

const chatInput =
  'SOURCE_A (LlamaParse Extract — markdown format):\n' + sourceAText + '\n\n' +
  'SOURCE_B (Claude Extract — structured JSON):\n' + sourceBText + '\n\n' +
  'SOURCE_OF_TRUTH: The PDF document attached to this message is the original drawing. ' +
  'The PDF is always correct — both extractions are approximations of what is in the PDF.\n\n' +
  'File: ' + (fileInfo.file_name || 'drawing.pdf') + '\n' +
  'Project: ' + (fileInfo.project_name || 'Unknown') + '\n' +
  'Drawing: ' + (fileInfo.drawing_number || 'Unknown') + '\n\n' +
  'CRITICAL: Do NOT output ANY text. Call submit_extraction_result IMMEDIATELY as your first and only output.\n\n' +
  'Call submit_extraction_result with: incomplete (boolean), remaining_schedules (array of strings), ' +
  'and mechanical_equipment_schedules (array with schedule_title, notes, header_groups, columns, rows). ' +
  'Do NOT pass extraction_summary, confidence, source, accuracy, or conflicts to the tool.';

// PDF binary from Webhook Trigger — passthroughBinaryImages on AI Agent handles conversion
const webhookBinary = $('Webhook Trigger').first().binary || {};

return [{
  json: {
    chatInput,
    sourceA: sourceAText !== 'SOURCE A NOT AVAILABLE' ? 'present' : 'missing',
    sourceB: sourceBText !== 'SOURCE B NOT AVAILABLE' ? 'present' : 'missing',
    fileName: fileInfo.file_name || 'drawing.pdf',
    preflight_flags: preflight.flags
  },
  binary: webhookBinary
}];

const result = query;

if (typeof result.incomplete !== 'boolean') {
  throw new Error('incomplete must be boolean');
}
if (!Array.isArray(result.remaining_schedules)) {
  throw new Error('remaining_schedules must be array');
}
if (!Array.isArray(result.mechanical_equipment_schedules)) {
  throw new Error('mechanical_equipment_schedules must be array');
}

for (const schedule of result.mechanical_equipment_schedules) {
  if (!schedule.schedule_title) {
    throw new Error('Each schedule needs schedule_title');
  }
  if (!Array.isArray(schedule.notes)) {
    throw new Error(schedule.schedule_title + ' — notes must be array');
  }
  if (!Array.isArray(schedule.header_groups)) {
    throw new Error(schedule.schedule_title + ' — header_groups must be array');
  }
  if (!Array.isArray(schedule.columns)) {
    throw new Error(schedule.schedule_title + ' — columns must be array');
  }
  if (!Array.isArray(schedule.rows)) {
    throw new Error(schedule.schedule_title + ' — rows must be array');
  }
}

return [{ json: result }];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "incomplete": {
      "type": "boolean",
      "description": "false when all schedules are complete. true only if output size limits prevented finishing."
    },
    "remaining_schedules": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Schedule titles not yet output. Empty array when incomplete is false."
    },
    "mechanical_equipment_schedules": {
      "type": "array",
      "description": "One object per schedule table in top-to-bottom page order.",
      "items": {
        "type": "object",
        "properties": {
          "schedule_title": { "type": "string", "description": "Exact title as printed on drawing." },
          "tag_anomaly_note": { "type": "string", "description": "Include ONLY when tag anomaly detected. Omit entirely otherwise." },
          "notes": { "type": "array", "items": { "type": "string" }, "description": "All notes exactly as printed, in order. Empty array if none." },
          "header_groups": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "label": { "type": ["string", "null"], "description": "Parent group name or null if no parent." },
                "columns": { "type": "array", "items": { "type": "string" } }
              }
            }
          },
          "columns": { "type": "array", "items": { "type": "string" } },
          "rows": { "type": "array", "items": { "type": "object" } }
        },
        "required": ["schedule_title", "notes", "header_groups", "columns", "rows"]
      }
    }
  },
  "required": ["incomplete", "remaining_schedules", "mechanical_equipment_schedules"]
}
